solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>

void *double_value(void *arg) {
    int *p = (int *)arg;
    *p *= 2;
    return NULL;
}

int run_thread(int *val) {
    pthread_t tid;
    if (pthread_create(&tid, NULL, double_value, val) != 0)
        return -1;
    if (pthread_join(tid, NULL) != 0)
        return -1;
    return 0;
}

int main(void) {
    int x = 5;
    if (run_thread(&x) == 0)
        printf("%d\n", x);
    return 0;
}
